class Solution:
    def findDuplicate(self, paths: List[str]) -> List[List[str]]:
        content_to_paths = {}
        for path in paths:
            files = path.split()
            dir_path = files[0]
            for file in files[1:]:
                file_name, file_content = file.split('(', 1)
                file_content = file_content[:-1]
                if file_content not in content_to_paths:
                    content_to_paths[file_content] = [file_path for file_path in [dir_path + '/' + file_name] if file_path not in content_to_paths]
                else:
                    content_to_paths[file_content].append(dir_path + '/' + file_name)
        return [paths for paths in content_to_paths.values() if len(paths) > 1]
